import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"Manual Entry","description":"","frontmatter":{},"headers":[],"relativePath":"guide/manual-entry.md","filePath":"guide/manual-entry.md","lastUpdated":1772287587000}'),n={name:"guide/manual-entry.md"};function s(i,e,l,d,u,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="manual-entry" tabindex="-1">Manual Entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual Entry&quot;">​</a></h1><p>If you have lab results but no PDF — for example, values written on paper, a result emailed as plain text, or numbers from a health device — you can enter them directly into getbased using the manual entry form.</p><h2 id="no-ai-provider-needed" tabindex="-1">No AI Provider Needed <a class="header-anchor" href="#no-ai-provider-needed" aria-label="Permalink to &quot;No AI Provider Needed&quot;">​</a></h2><p>Manual entry does not use AI. You don&#39;t need an API key or any provider configured to use it.</p><h2 id="how-to-use-manual-entry" tabindex="-1">How to Use Manual Entry <a class="header-anchor" href="#how-to-use-manual-entry" aria-label="Permalink to &quot;How to Use Manual Entry&quot;">​</a></h2><ol><li>In the sidebar, click <strong>Manual Entry</strong> (or find it in the navigation menu on mobile)</li><li>Select the <strong>date</strong> of the lab draw</li><li>Browse or search for markers by name or category</li><li>Enter the value for each marker you have results for</li><li>Click <strong>Save</strong></li></ol><p>The results are saved immediately and appear in your charts alongside any PDF-imported data.</p><div class="tip custom-block"><p class="custom-block-title">You don&#39;t need to fill in everything</p><p>Only enter the markers you have results for. Leave the rest blank. getbased uses <code>null</code> for missing values and draws chart lines across gaps automatically.</p></div><h2 id="finding-markers" tabindex="-1">Finding Markers <a class="header-anchor" href="#finding-markers" aria-label="Permalink to &quot;Finding Markers&quot;">​</a></h2><p>The marker list is organized by the same 15 categories used throughout the app (biochemistry, hormones, lipids, etc.). You can scroll through a category or use the search box to find a marker by name.</p><p>If a marker you&#39;re looking for doesn&#39;t appear in the list, it may be a custom marker from a previous PDF import. Custom markers also appear in the manual entry list once they&#39;ve been created.</p><h2 id="editing-existing-values" tabindex="-1">Editing Existing Values <a class="header-anchor" href="#editing-existing-values" aria-label="Permalink to &quot;Editing Existing Values&quot;">​</a></h2><p>To correct a value you&#39;ve already entered, import a new entry for the same date with the corrected value. Entries are merged by date, so the new value replaces the old one for that marker on that date.</p><div class="warning custom-block"><p class="custom-block-title">Units</p><p>Make sure you enter values in the units shown next to each marker. getbased stores data in SI units (EU mode) by default. If your results are in US units (e.g., mg/dL for glucose instead of mmol/L), switch to <strong>US units</strong> in <strong>Settings → Display</strong> before entering values, or convert manually.</p></div><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li>Results from a doctor&#39;s visit where only a printout was provided</li><li>Home test kits (cholesterol monitors, blood glucose meters, etc.)</li><li>Entering a single marker you noticed was missing after a PDF import</li><li>Historical values you&#39;ve tracked in a spreadsheet</li></ul>',16)])])}const p=a(n,[["render",s]]);export{m as __pageData,p as default};
